  const oldDir = join5(__dirname5, "..", "data");
  if (oldDir === dataDir) return;
  if (!existsSync4(oldDir)) return;
  if (existsSync4(join5(dataDir, "accounts.json"))) return;
  log5(`Migrating data from ${oldDir} to ${dataDir}`);
